/**
 * Main HIVE BLE adapter interface
 */
public protocol HiveAdapterProtocol : AnyObject {
    
    /**
     * Add a mock discovered peer (for testing)
     */
    func addMockPeer(name: String, rssi: Int8) 
    
    /**
     * Broadcast data to all connected peers
     */
    func broadcastData(data: Data) throws 
    
    /**
     * Connect to a discovered peer by identifier
     */
    func connect(identifier: String) throws 
    
    /**
     * Disconnect from a peer
     */
    func disconnect(peerId: UInt32) throws 
    
    /**
     * Disconnect all peers
     */
    func disconnectAll() 
    
    /**
     * Get current Bluetooth state
     */
    func getBluetoothState()  -> BluetoothState
    
    /**
     * Get connection info for a specific peer
     */
    func getConnection(peerId: UInt32)  -> ConnectionInfo?
    
    /**
     * Get list of active connections
     */
    func getConnections()  -> [ConnectionInfo]
    
    /**
     * Get list of discovered peers
     */
    func getDiscoveredPeers()  -> [DiscoveredPeer]
    
    /**
     * Get the local node ID
     */
    func getNodeId()  -> UInt32
    
    /**
     * Get sync statistics
     */
    func getSyncStats()  -> SyncStats
    
    /**
     * Check if advertising is active
     */
    func isAdvertising()  -> Bool
    
    /**
     * Check if scanning is active
     */
    func isDiscovering()  -> Bool
    
    /**
     * Check if the adapter is running
     */
    func isRunning()  -> Bool
    
    /**
     * Process pending events (call periodically from main thread)
     */
    func processEvents() 
    
    /**
     * Send data to a connected peer
     */
    func sendData(peerId: UInt32, data: Data) throws 
    
    /**
     * Set callback for connection events
     */
    func setConnectionCallback(callback: ConnectionCallback) 
    
    /**
     * Set callback for received data
     */
    func setDataCallback(callback: DataCallback) 
    
    /**
     * Set callback for discovery events
     */
    func setDiscoveryCallback(callback: DiscoveryCallback) 
    
    /**
     * Initialize and start the adapter
     */
    func start() throws 
    
    /**
     * Start advertising as a HIVE node
     */
    func startAdvertising() throws 
    
    /**
     * Start scanning for HIVE peers
     */
    func startDiscovery() throws 
    
    /**
     * Stop the adapter
     */
    func stop() throws 
    
    /**
     * Stop advertising
     */
    func stopAdvertising() throws 
    
    /**
     * Stop scanning
     */
    func stopDiscovery() throws 
    
    /**
     * Trigger manual sync with all connected peers
     */
    func triggerSync() throws 
    
}

