/**
 * Error types for the HIVE adapter
 */
public enum HiveError {

    
    
    case NotInitialized
    case AlreadyInitialized
    case NotRunning
    case BluetoothUnavailable
    case BluetoothUnauthorized
    case ConnectionFailed(reason: String
    )
    case SendFailed(reason: String
    )
    case Timeout
    case InvalidState
    case Internal(message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeHiveError: FfiConverterRustBuffer {
    typealias SwiftType = HiveError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HiveError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .NotInitialized
        case 2: return .AlreadyInitialized
        case 3: return .NotRunning
        case 4: return .BluetoothUnavailable
        case 5: return .BluetoothUnauthorized
        case 6: return .ConnectionFailed(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 7: return .SendFailed(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 8: return .Timeout
        case 9: return .InvalidState
        case 10: return .Internal(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

